import torch
import torch.nn as nn

class VAEGenerator(nn.Module):
    """Wraps a trained decoder for unconditional generation."""

    def __init__(self, decoder: nn.Module, z_dim: int):
        super().__init__()
        self.decoder = decoder
        self.z_dim = z_dim

    @torch.no_grad()
    def sample(self, n: int, device: torch.device) -> torch.Tensor:
        """Draw n samples from p(z) and decode them."""
        z = torch.randn(n, self.z_dim, device=device)   # z ~ N(0, I)
        return self.decoder(z)                          # x_hat ~ p_θ(x|z)

    @torch.no_grad()
    def sample_with_temperature(self, n: int, temperature: float,
                                device: torch.device) -> torch.Tensor:
        """Scale the prior variance by temperature^2."""
        z = torch.randn(n, self.z_dim, device=device) * temperature
        return self.decoder(z)


